import React from "react";
import { Form, Col, Button } from "react-bootstrap";
import { Link } from "react-router-dom";

function FormComponent({ info, handleBtn, params, link }) {
  const path = `/decks/${link}`;

  function resestForm() {
    document.getElementById("front").value = "";
    document.getElementById("back").value = "";
  }

  // Buttons for edit card
  const editBtns = () => {
    return (
      <div>
        <Link to={`/decks/${params.deckId}`}>
          <Button className="mt-2 mr-1" variant="secondary">
            Cancel
          </Button>
        </Link>
        <Link to={`/decks/${params.deckId}`}>
          <Button onClick={() => handleBtn()} className="mt-2 mr-1">
            Submit
          </Button>
        </Link>
      </div>
    );
  };

  // Buttons for add card
  const addBtns = () => {
    return (
      <div>
        <Link to={`/decks/${params.deckId}`}>
          <Button className="mt-2 mr-1" variant="secondary">
            Done
          </Button>
        </Link>
        <Button
          onClick={() => {
            handleBtn();
            resestForm();
          }}
          className="mt-2 mr-1"
        >
          Save
        </Button>
      </div>
    );
  };

  // Main form
  return (
    <div>
      <Form>
        <Col>
          <h1>{info.name ? info.name : null} Add Card</h1>
          <Form.Label className="mt-1">Front</Form.Label>
          <Form.Control
            className="mt-1"
            placeholder="Front of card"
            as="textarea"
            id="front"
          ></Form.Control>
          <Form.Label className="mt-1">Back</Form.Label>
          <Form.Control
            className="mt-1"
            placeholder="Back of card"
            as="textarea"
            id="back"
          ></Form.Control>
          {link ? editBtns() : addBtns()}
        </Col>
      </Form>
    </div>
  );
}

export default FormComponent;
